CREATE TABLE IF NOT EXISTS llm_invocation (id VARCHAR(64) PRIMARY KEY,job_claw_user_id VARCHAR(64),conversation_id VARCHAR(255),channel VARCHAR(64),agent VARCHAR(128),operation VARCHAR(128),mode VARCHAR(32),outcome VARCHAR(32),duration_ms BIGINT,request_count INT,input_tokens BIGINT,output_tokens BIGINT,total_tokens BIGINT,estimated_cost DECIMAL(20,8),error_message VARCHAR(2000),create_time TIMESTAMP,INDEX idx_llm_inv_user_time (job_claw_user_id,create_time),INDEX idx_llm_inv_agent_time (agent,create_time));
CREATE TABLE IF NOT EXISTS llm_request (id VARCHAR(64) PRIMARY KEY,invocation_id VARCHAR(64),job_claw_user_id VARCHAR(64),conversation_id VARCHAR(255),channel VARCHAR(64),agent VARCHAR(128),operation VARCHAR(128),mode VARCHAR(32),provider VARCHAR(128),model VARCHAR(255),model_type VARCHAR(32),outcome VARCHAR(32),duration_ms BIGINT,input_tokens BIGINT,output_tokens BIGINT,total_tokens BIGINT,estimated_cost DECIMAL(20,8),error_message VARCHAR(2000),prompt_sample LONGTEXT,response_sample LONGTEXT,create_time TIMESTAMP,INDEX idx_llm_req_invocation (invocation_id),INDEX idx_llm_req_user_time (job_claw_user_id,create_time));
